{
  "sentences": [
    {
      "text": "公寓在學校附近。",
      "pinyin": "Gōngyù zài xuéxiào fùjìn.",
      "pinyin_numeric": "gong1yu4 zai4 xue2xiao4 fu4jin4",
      "translation_en": "The apartment is near the school.",
      "translation_ko": "아파트가 학교 근처에 있습니다."
    },
    {
      "text": "客廳在廚房的旁邊。",
      "pinyin": "Kètīng zài chúfáng de pángbiān.",
      "pinyin_numeric": "ke4ting1 zai4 chu2fang2 de pang2bian1",
      "translation_en": "The living room is next to the kitchen.",
      "translation_ko": "거실이 부엌 옆에 있습니다."
    },
    {
      "text": "浴室在房間的裡面。",
      "pinyin": "Yùshì zài fángjiān de lǐmiàn.",
      "pinyin_numeric": "yu4shi4 zai4 fang2jian1 de li3mian4",
      "translation_en": "The bathroom is inside the room.",
      "translation_ko": "욕실이 방 안에 있습니다."
    },
    {
      "text": "陽台在客廳的外面。",
      "pinyin": "Yángtái zài kètīng de wàimiàn.",
      "pinyin_numeric": "yang2tai2 zai4 ke4ting1 de wai4mian4",
      "translation_en": "The balcony is outside the living room.",
      "translation_ko": "발코니가 거실 밖에 있습니다."
    },
    {
      "text": "床在窗戶的旁邊。",
      "pinyin": "Chuáng zài chuānghù de pángbiān.",
      "pinyin_numeric": "chuang2 zai4 chuang1hu4 de pang2bian1",
      "translation_en": "The bed is next to the window.",
      "translation_ko": "침대가 창문 옆에 있습니다."
    },
    {
      "text": "書桌在衣櫃的前面。",
      "pinyin": "Shūzhuō zài yīguì de qiánmiàn.",
      "pinyin_numeric": "shu1zhuo1 zai4 yi1gui4 de qian2mian4",
      "translation_en": "The desk is in front of the wardrobe.",
      "translation_ko": "책상이 옷장 앞에 있습니다."
    },
    {
      "text": "冰箱在廚房的水槽旁邊。",
      "pinyin": "Bīngxiāng zài chúfáng de shuǐcáo pángbiān.",
      "pinyin_numeric": "bing1xiang1 zai4 chu2fang2 de shui3cao2 pang2bian1",
      "translation_en": "The refrigerator is next to the kitchen sink.",
      "translation_ko": "냉장고가 부엌 싱크대 옆에 있습니다."
    },
    {
      "text": "洗衣機在浴室的裡面。",
      "pinyin": "Xǐyījī zài yùshì de lǐmiàn.",
      "pinyin_numeric": "xi3yi1ji1 zai4 yu4shi4 de li3mian4",
      "translation_en": "The washing machine is inside the bathroom.",
      "translation_ko": "세탁기가 욕실 안에 있습니다."
    },
    {
      "text": "沙發在客廳的中間。",
      "pinyin": "Shāfā zài kètīng de zhōngjiān.",
      "pinyin_numeric": "sha1fa1 zai4 ke4ting1 de zhong1jian1",
      "translation_en": "The sofa is in the middle of the living room.",
      "translation_ko": "소파가 거실 중간에 있습니다."
    },
    {
      "text": "電視在沙發的對面。",
      "pinyin": "Diànshì zài shāfā de duìmiàn.",
      "pinyin_numeric": "dian4shi4 zai4 sha1fa1 de dui4mian4",
      "translation_en": "The TV is opposite the sofa.",
      "translation_ko": "텔레비전이 소파 맞은편에 있습니다."
    }
  ]
}
